import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [step, setStep] = useState<1 | 2 | 3 | 4 | 5>(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation errors
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Helper: validate email format
  const isValidEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  // Helper: validate step 1
  const isStep1Valid = useCallback((): boolean => {
    let isValid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!isValidEmail(email)) {
      setEmailError('Please enter a valid email address');
      isValid = false;
    } else {
      setEmailError('');
    }
    return isValid;
  }, [name, email, isValidEmail]);

  // Handle name change with validation
  const handleNameChange = useCallback((value: string) => {
    setName(value);
    if (nameError) setNameError('');
  }, [nameError]);

  // Handle email change with validation
  const handleEmailChange = useCallback((value: string) => {
    setEmail(value);
    if (emailError) setEmailError('');
  }, [emailError]);

  // Handle next button
  const handleNext = useCallback(() => {
    if (step === 1) {
      if (isStep1Valid()) {
        setStep(2);
      }
      return;
    }
    if (step === 2 && !satisfaction) {
      return;
    }
    if (step < 5) {
      setStep((prev) => (prev + 1) as 1 | 2 | 3 | 4 | 5);
    }
  }, [step, isStep1Valid, satisfaction]);

  // Handle back button
  const handleBack = useCallback(() => {
    if (step > 1) {
      setStep((prev) => (prev - 1) as 1 | 2 | 3 | 4 | 5);
    }
  }, [step]);

  // Handle feature checkbox change
  const handleFeatureChange = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  // Handle form submission
  const handleSubmit = useCallback(() => {
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments,
    });
  }, [name, email, satisfaction, features, comments, submit]);

  // Compute progress percentage
  const progressPercent = ((step - 1) / 4) * 100;

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Survey Form</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Step {step} of 5
          </Text>
        </Stack>

        {/* Progress bar */}
        <Progress value={progressPercent} max={100} size="md" />

        {/* Step 1: Name and Email */}
        {step === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your name"
                value={name}
                onChange={handleNameChange}
                error={nameError}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="Enter your email"
                value={email}
                onChange={handleEmailChange}
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {step === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you with our service?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: String(index + 1),
                  label: label,
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {step === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Feature Interests</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Select all features you are interested in:
              </Text>
              <Stack gap="var(--ggui-spacing-3)">
                {props.featureOptions.map((option) => (
                  <Checkbox
                    key={option}
                    label={option}
                    checked={features.includes(option)}
                    onChange={() => handleFeatureChange(option)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {step === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Please share any additional feedback or comments..."
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {step === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-3)" direction="vertical">
                <Box paddingY="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Name
                  </Text>
                  <Text>{name}</Text>
                </Box>
                <Divider />
                <Box paddingY="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Email
                  </Text>
                  <Text>{email}</Text>
                </Box>
                <Divider />
                <Box paddingY="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Satisfaction Rating
                  </Text>
                  <Text>
                    {props.satisfactionLabels[parseInt(satisfaction, 10) - 1] || 'Not selected'}
                  </Text>
                </Box>
                <Divider />
                <Box paddingY="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Interested Features
                  </Text>
                  {features.length > 0 ? (
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" wrap>
                      {features.map((feature) => (
                        <Badge key={feature} variant="primary">
                          {feature}
                        </Badge>
                      ))}
                    </Stack>
                  ) : (
                    <Text color="var(--ggui-color-onSurfaceVariant)">None selected</Text>
                  )}
                </Box>
                <Divider />
                <Box paddingY="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Comments
                  </Text>
                  <Text>{comments || '(No comments provided)'}</Text>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1}
          >
            Back
          </Button>
          {step < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (step === 1 && !isStep1Valid()) ||
                (step === 2 && !satisfaction)
              }
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

