// Helper function to render star rating
function renderStars(rating: number | undefined) {
  if (!rating) return null;
  const stars = [];
  for (let i = 1; i <= 5; i++) {
    stars.push(
      <Icon
        key={i}
        name={i <= rating ? 'star' : 'star-outline'}
        size={20}
        color={i <= rating ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}
      />
    );
  }
  return stars;
}

// Helper function to get stock status
function getStockStatus(stock: number | undefined) {
  if (!stock) return { label: 'Out of Stock', variant: 'error' as const };
  if (stock <= 10) return { label: 'Low Stock', variant: 'warning' as const };
  return { label: 'In Stock', variant: 'success' as const };
}

