interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // Local state
  const [allMessages, setAllMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const [typingUser, setTypingUser] = useState<{ sender?: string; active?: boolean } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Handle incoming messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      setTypingUser(typing.latest);
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const newMessage = {
        sender: props.currentUser,
        text: inputValue,
        timestamp: new Date().toISOString(),
      };
      setAllMessages((prev) => [...prev, newMessage]);
      sendMessage({ text: inputValue, timestamp: new Date().toISOString() });
      setInputValue('');
    }
  }, [inputValue, props.currentUser, sendMessage]);

  // Handle Enter key to send
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        groups.push({ sender: msg.sender, messages: [msg] });
      }
    });

    return groups;
  }, [allMessages]);

  // Format timestamp
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  const isCurrentUser = (sender?: string) => sender === props.currentUser;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-4)" radius="lg" border={true}>
        <Stack gap="var(--ggui-spacing-4)" direction="vertical">
          {/* Header */}
          <Box paddingX="var(--ggui-spacing-4)" paddingY="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
            <Row justify="between" align="center">
              <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
                <Heading level={4} color="var(--ggui-color-onSurface)">{props.title}</Heading>
                <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
              </Stack>
              {typingUser?.active && typingUser?.sender && (
                <Stack gap="var(--ggui-spacing-1)" direction="horizontal" align="center">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {typingUser.sender} is typing
                  </Text>
                  <Spinner size={16} color="var(--ggui-color-primary-600)" />
                </Stack>
              )}
            </Row>
          </Box>

          {/* Message List */}
          <Box
            paddingX="var(--ggui-spacing-4)"
            paddingY="var(--ggui-spacing-3)"
            style={{
              maxHeight: '400px',
              overflowY: 'auto',
              borderRadius: 'var(--ggui-shape-radius-md)',
              backgroundColor: 'var(--ggui-color-surface)',
              border: '1px solid var(--ggui-color-outlineVariant)',
            }}
          >
            <Stack gap="var(--ggui-spacing-3)" direction="vertical">
              {groupedMessages.length === 0 ? (
                <Box padding="var(--ggui-spacing-4)" style={{ textAlign: 'center' }}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    No messages yet. Start the conversation!
                  </Text>
                </Box>
              ) : (
                groupedMessages.map((group, groupIdx) => {
                  const isOwn = isCurrentUser(group.sender);
                  return (
                    <Stack
                      key={groupIdx}
                      gap="var(--ggui-spacing-2)"
                      direction="vertical"
                      align={isOwn ? 'end' : 'start'}
                      style={{
                        maxWidth: '70%',
                        marginLeft: isOwn ? 'auto' : 'var(--ggui-spacing-2)',
                        marginRight: isOwn ? 'var(--ggui-spacing-2)' : 'auto',
                      }}
                    >
                      {/* Sender name (for non-current user) */}
                      {!isOwn && (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
                          {group.sender || 'Unknown'}
                        </Text>
                      )}
                      {/* Messages in group */}
                      <Stack gap="var(--ggui-spacing-1)" direction="vertical">
                        {group.messages.map((msg, msgIdx) => (
                          <Box
                            key={msgIdx}
                            padding="var(--ggui-spacing-3)"
                            background={
                              isOwn
                                ? 'var(--ggui-color-primary-600)'
                                : 'var(--ggui-color-surfaceVariant)'
                            }
                            borderRadius="var(--ggui-shape-radius-md)"
                          >
                            <Text
                              variant="body"
                              color={
                                isOwn
                                   ? 'var(--ggui-color-onPrimary)'
                                  : 'var(--ggui-color-onSurface)'
                              }
                            >
                              {msg.text || ''}
                            </Text>
                          </Box>
                        ))}
                      </Stack>
                      {/* Timestamp (on last message of group) */}
                      {group.messages[group.messages.length - 1]?.timestamp && (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {formatTime(group.messages[group.messages.length - 1].timestamp)}
                        </Text>
                      )}
                    </Stack>
                  );
                })
              )}
              {/* Scroll anchor */}
              <div ref={messagesEndRef} />
            </Stack>
          </Box>

          {/* Input Area */}
          <Stack gap="var(--ggui-spacing-2)" direction="vertical">
            <TextArea
              label="Message"
              value={inputValue}
              onChange={setInputValue}
              placeholder="Type your message..."
              rows={3}
              style={{
                resize: 'none',
              }}
            />
            <Row justify="end" gap="var(--ggui-spacing-2)">
              <Button
                variant="primary"
                onClick={handleSendMessage}
                disabled={!inputValue.trim()}
              >
                Send
              </Button>
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

