import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touchedName, setTouchedName] = useState(false);
  const [touchedEmail, setTouchedEmail] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const safeSatisfactionLabels = Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [];
  const safeFeatureOptions = Array.isArray(props.featureOptions) ? props.featureOptions : [];

  const nameError = touchedName && name.trim() === '' ? 'Name is required' : '';
  const emailError = touchedEmail && email.trim() === ''
    ? 'Email is required'
    : touchedEmail && !EMAIL_REGEX.test(email.trim())
      ? 'Please enter a valid email address'
      : '';

  const isStep1Valid = name.trim() !== '' && EMAIL_REGEX.test(email.trim());
  const isStep2Valid = satisfaction !== '';
  const isCurrentStepValid = step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true;
  const progressValue = (step / 5) * 100;
  const commentsCount = comments.length;

  const satisfactionOptions = safeSatisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const handleFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        return prev.includes(feature) ? prev : [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
      if (!isStep1Valid) {
        return;
      }
    }
    if (step === 2 && !isStep2Valid) {
      return;
    }
    if (step < 5) {
      setStep((prev) => prev + 1);
    }
  }, [step, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (step > 1) {
      setStep((prev) => prev - 1);
    }
  }, [step]);

  const handleSubmit = useCallback(() => {
    if (!isStep1Valid || !isStep2Valid) {
      return;
    }
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments,
    });
    setSubmitted(true);
  }, [submit, name, email, satisfaction, features, comments, isStep1Valid, isStep2Valid]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface)">Survey Form</Heading>
              <Badge variant="primary">Step {step} of 5</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" />
          </Stack>
        </Card>

        {submitted && (
          <Alert variant="success" title="Submitted">
            Thank you! Your survey response has been submitted.
          </Alert>
        )}

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-4)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Your Information</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={nameError}
                  onBlur={() => setTouchedName(true)}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="Enter your email"
                  error={emailError}
                  onBlur={() => setTouchedEmail(true)}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction Rating</Heading>
                {satisfactionOptions.length > 0 ? (
                  <RadioGroup
                    label="How satisfied are you?"
                    value={satisfaction}
                    onChange={setSatisfaction}
                    options={satisfactionOptions}
                    direction="vertical"
                    error={satisfaction === '' ? 'Please select a rating to continue' : ''}
                  />
                ) : (
                  <Alert variant="warning" title="No rating labels">
                    Satisfaction options are currently unavailable.
                  </Alert>
                )}
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature Interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Select all features you are interested in.</Text>
                {safeFeatureOptions.length > 0 ? (
                  <Stack gap="var(--ggui-spacing-2)">
                    {safeFeatureOptions.map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => handleFeatureToggle(feature, checked)}
                      />
                    ))}
                  </Stack>
                ) : (
                  <Alert variant="warning" title="No feature options">
                    Feature options are currently unavailable.
                  </Alert>
                )}
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Additional Comments</Heading>
                <TextArea
                  label="Comments"
                  value={comments}
                  onChange={setComments}
                  placeholder="Share any additional thoughts (optional)"
                  maxLength={500}
                  showCount
                  helperText={`${commentsCount}/500 characters`}
                  rows={6}
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Review Your Answers</Heading>
                <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Satisfaction:</Text> {satisfaction ? `${satisfaction} - ${safeSatisfactionLabels[Number(satisfaction) - 1] || ''}` : '—'}</Text>
                    <Text><Text is="span" weight="semibold">Features:</Text> {features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() || 'No comments'}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />
            <Row justify="between" align="center">
              <Button variant="outline" onClick={handleBack} disabled={step === 1}>
                Back
              </Button>
              {step < 5 ? (
                <Button variant="primary" onClick={handleNext} disabled={!isCurrentStepValid && step !== 3 && step !== 4}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>
                  Submit
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

