  const [newTaskPriorityByColumn, setNewTaskPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    setLocalTasks(props.tasks || []);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = taskChanged.latest.task;
    const incomingId = incoming.id || '';
    if (!incomingId) return;

    setLocalTasks((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((task) => task.id !== incomingId);
      }
      const exists = prev.some((task) => task.id === incomingId);
      if (!exists) return [...prev, incoming];
      return prev.map((task) => (task.id === incomingId ? { ...task, ...incoming } : task));
    });
  }, [taskChanged.latest]);

  const columnsToRender = useMemo(() => {
    if (props.columns && props.columns.length > 0) return props.columns;
    return [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' },
    ];
  }, [props.columns]);

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>> = {};
    columnsToRender.forEach((column) => {
      grouped[column.id || ''] = [];
    });
    (localTasks || []).forEach((task) => {
      const col = task.column || 'todo';
      if (!grouped[col]) grouped[col] = [];
      grouped[col].push(task);
    });
    return grouped;
  }, [localTasks, columnsToRender]);

  const completedCount = useMemo(() => {
    const doneColumn = columnsToRender.find((column) => (column.name || '').toLowerCase() === 'done' || column.id === 'done');
    if (!doneColumn || !doneColumn.id) return 0;
    return (tasksByColumn[doneColumn.id] || []).length;
  }, [columnsToRender, tasksByColumn]);

  const moveTask = useCallback(
    (taskId: string, nextColumn: string) => {
      if (!taskId || !nextColumn) return;
      setLocalTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task)));
      taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
    },
    [taskUpdate]
  );

  const saveEditTask = useCallback(
    (taskId: string) => {
      if (!taskId || !editingTitle.trim()) return;
      const finalTitle = editingTitle.trim();
      setLocalTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: finalTitle } : task)));
      setEditingTaskId('');
      setEditingTitle('');
      taskUpdate({ action: 'edit', taskId, data: { column: '', title: finalTitle } as { column: string } });
    },
    [editingTitle, taskUpdate]
  );

  const createTask = useCallback(
    (columnId: string) => {
      const title = (newTaskTitleByColumn[columnId] || '').trim();
      if (!title) return;
      const taskId = `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      const newTask = {
        id: taskId,
        title,
        priority: newTaskPriorityByColumn[columnId] || 'low',
        assignee: 'Unassigned',
        column: 'todo',
        dueDate: '',
      } as { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
      setLocalTasks((prev) => [...prev, newTask]);
      setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
      setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: 'low' }));
      setAddingByColumn((prev) => ({ ...prev, [columnId]: false }));
      taskUpdate({ action: 'create', taskId, data: { column: 'todo', title, priority: newTask.priority || 'low', assignee: newTask.assignee || '', dueDate: newTask.dueDate || '' } as { column: string } });
    },
    [newTaskPriorityByColumn, newTaskTitleByColumn, taskUpdate]
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center" wrap>
            <Heading level={3}>Kanban Task Board</Heading>
            <Row gap="var(--ggui-spacing-4)" align="center">
              <Badge variant="primary">Total: {(localTasks || []).length}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
              <Badge variant={taskChanged.latest ? 'info' : 'default'}>
                Updates: {taskChanged.all.length}
              </Badge>
            </Row>
          </Row>
        </Card>

        <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={16}>
          {columnsToRender.map((column) => {
            const columnId = column.id || '';
            const colTasks = tasksByColumn[columnId] || [];
            return (
              <Card key={columnId || column.name} padding="var(--ggui-spacing-4)" shadow="sm" border>
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name || 'Untitled'}</Heading>
                    <Badge variant="default">{colTasks.length}</Badge>
                  </Row>
                  <Divider margin="var(--ggui-spacing-1)" />

                  <Stack gap="var(--ggui-spacing-3)">
                    {colTasks.length === 0 ? (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No tasks in this column.
                      </Text>
                    ) : (
                      colTasks.map((task) => {
                        const taskId = task.id || '';
                        const isEditing = editingTaskId === taskId;
                        return (
                          <Card key={taskId} padding="var(--ggui-spacing-3)" shadow="none" border>
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row justify="between" align="center">
                                {isEditing ? (
                                  <Input
                                    label="Edit task title"
                                    value={editingTitle}
                                    onChange={setEditingTitle}
                                    placeholder="Task title"
                                  />
                                ) : (
                                  <Text as={Clickable} onClick={() => {}} onDoubleClick={() => { if (!taskId) return; setEditingTaskId(taskId); setEditingTitle(task.title || ''); }} weight="medium">{task.title || 'Untitled task'}</Text>
                                )}
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => {
                                    if (!taskId) return;
                                    if (isEditing) {
                                      saveEditTask(taskId);
                                    } else {
                                      setEditingTaskId(taskId);
                                      setEditingTitle(task.title || '');
                                    }
                                  }}
                                >
                                  {isEditing ? 'Save' : 'Edit'}
                                </Button>
                              </Row>

                              <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                                <Badge variant={getPriorityVariant(task.priority)}>{task.priority || 'low'}</Badge>
                                <Row gap="var(--ggui-spacing-1)" align="center">
                                  <Avatar name={task.assignee || 'Unassigned'} size="xs" />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    {task.assignee || getInitials(task.assignee)}
                                  </Text>
                                </Row>
                                {task.dueDate ? (
                                  <Badge variant="info">Due: {task.dueDate}</Badge>
                                ) : (
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    No due date
                                  </Text>
                                )}
                              </Row>

                              <Select
                                label="Move task"
                                value={task.column || ''}
                                onChange={(value) => moveTask(taskId, value)}
                                options={columnsToRender
                                  .filter((c) => !!c.id)
                                  .map((c) => ({ value: c.id || '', label: c.name || c.id || 'Column' }))}
                              />
                            </Stack>
                          </Card>
                        );
                      })
                    )}
                  </Stack>

                  {addingByColumn[columnId] ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="none" border>
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitleByColumn[columnId] || ''}
                          onChange={(value) => setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: value }))}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriorityByColumn[columnId] || 'low'}
                          onChange={(value) =>
                            setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: value as 'low' | 'medium' | 'high' }))
                          }
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button variant="primary" size="sm" onClick={() => createTask(columnId)}>Create</Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => setAddingByColumn((prev) => ({ ...prev, [columnId]: false }))}
                          >
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : null}

                  <Box as={Clickable} onClick={() => setAddingByColumn((prev) => ({ ...prev, [columnId]: true }))}>
                    <Button variant="outline" size="sm" fullWidth>Add Task</Button>
                  </Box>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

