  return colorMap[key] || 'var(--ggui-color-surfaceVariant)';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedElements = useMemo(() => {
    return (props.elements || []).map((element) => ({
      ...element,
      category: element.category || 'unknown',
      name: element.name || 'Unknown',
      symbol: element.symbol || '?',
      atomicNumber: element.atomicNumber ?? -1,
      atomicWeight: element.atomicWeight ?? 0,
      row: element.row ?? 1,
      col: element.col ?? 1,
    }));
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!query) return normalizedElements;
    return normalizedElements.filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [normalizedElements, searchQuery]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return normalizedElements.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [normalizedElements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    normalizedElements.forEach((element) => unique.add((element.category || 'unknown').toLowerCase()));
    return Array.from(unique).sort();
  }, [normalizedElements]);

  useEffect(() => {
    if (selectedAtomicNumber === null) return;
    const stillExists = normalizedElements.some((e) => e.atomicNumber === selectedAtomicNumber);
    if (!stillExists) setSelectedAtomicNumber(null);
  }, [normalizedElements, selectedAtomicNumber]);

  return (
