                      ? 'var(--ggui-color-primary-600)'
                      : 'var(--ggui-color-outline)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {element.atomicNumber}
                    </Text>
                    <Text variant="bodyLarge" weight="bold" align="center">
                      {element.symbol}
                    </Text>
                  </Stack>
                </Card>
              ))}
            </Box>
