              <Text color="var(--ggui-color-onSurfaceVariant)">Click an element to view details.</Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
