function formatPrice(value: number | undefined, currency: string | undefined): string {
  const safeValue = typeof value === 'number' ? value : 0;
  if (currency && currency.trim().length > 0) {
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency }).format(safeValue);
    } catch (_error) {
      return `${currency} ${safeValue.toFixed(2)}`;
    }
  }
  return safeValue.toFixed(2);
}

function getStars(rating: number | undefined): string[] {
  const safeRating = Math.max(0, Math.min(5, Math.round(rating ?? 0)));
  return Array.from({ length: 5 }, (_v, i) => (i < safeRating ? '★' : '☆'));
}

function readSpecPair(item: unknown, index: number): { key: string; value: string } {
  if (item && typeof item === 'object') {
    const asRecord = item as Record<string, unknown>;
    const key = typeof asRecord.key === 'string' ? asRecord.key : typeof asRecord.name === 'string' ? asRecord.name : `Spec ${index + 1}`;
    const valueRaw = asRecord.value;
    const value = typeof valueRaw === 'string' || typeof valueRaw === 'number' || typeof valueRaw === 'boolean' ? String(valueRaw) : '—';
    return { key, value };
  }
  return { key: `Spec ${index + 1}`, value: String(item ?? '—') };
}

function readReview(item: unknown, index: number): { author: string; rating: number; text: string; date: string } {
  if (item && typeof item === 'object') {
    const asRecord = item as Record<string, unknown>;
    const author = typeof asRecord.author === 'string' ? asRecord.author : `Reviewer ${index + 1}`;
    const rating = typeof asRecord.rating === 'number' ? asRecord.rating : 0;
    const text = typeof asRecord.text === 'string' ? asRecord.text : '';
    const date = typeof asRecord.date === 'string' ? asRecord.date : '';
    return { author, rating, text, date };
  }
  return { author: `Reviewer ${index + 1}`, rating: 0, text: String(item ?? ''), date: '' };
}

