              {typingLabel || ' '}
            </Text>
          </Row>

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
          >
            <Stack gap="var(--ggui-spacing-2)">
              <Box>
                <Box
                  padding="var(--ggui-spacing-2)"
                  background="var(--ggui-color-surface)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Box>
                    <div
                      ref={listRef}
                      style={{
                        maxHeight: '60vh',
                        overflowY: 'auto',
                        display: 'flex',
                        flexDirection: 'column',
                        gap: 'var(--ggui-spacing-3)',
                        padding: 'var(--ggui-spacing-2)',
                      }}
                    >
                      {groupedMessages.length === 0 ? (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                          No messages yet
                        </Text>
                      ) : (
                        groupedMessages.map((group, groupIndex) => {
                          const isCurrentUser = (group.sender ?? '') === props.currentUser;
                          return (
                            <Stack key={(group.sender ?? 'unknown') + '-' + String(groupIndex)} gap="var(--ggui-spacing-1)" align={isCurrentUser ? 'end' : 'start'}>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {group.sender || 'Unknown'}
                              </Text>
                              {group.items.map((item, itemIndex) => (
                                <Box
                                  key={(item.timestamp ?? 't') + '-' + String(itemIndex)}
                                  padding="var(--ggui-spacing-2)"
                                  background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                                  borderRadius="var(--ggui-shape-radius-md)"
                                >
                                  <Stack gap="var(--ggui-spacing-1)">
                                    <Text
                                      variant="bodySmall"
                                      color={isCurrentUser ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}
                                    >
                                      {item.text || ''}
                                    </Text>
                                    <Text
                                      variant="caption"
                                      color={isCurrentUser ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}
                                    >
                                      {formatTimestamp(item.timestamp)}
                                    </Text>
                                  </Stack>
                                </Box>
                              ))}
                            </Stack>
                          );
                        })
                      )}
                    </div>
                  </Box>
                </Box>
              </Box>

              <Row gap="var(--ggui-spacing-2)" align="end">
                <Box style={{ flex: 1 } as React.CSSProperties}>
                  <Input
                    label="Message"
                    placeholder="Type your message..."
                    value={draft}
                    onChange={setDraft}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter' && !event.shiftKey) {
                        event.preventDefault();
                        handleSend();
                      }
                    }}
                  />
                </Box>
                <Button variant="primary" disabled={!draft.trim()} onClick={handleSend}>
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
}

