type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Place helper components here if needed
type DisplayStock = {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
};

function formatPrice(value: number): string {
  return `$${value.toFixed(2)}`;
}

function formatSigned(value: number): string {
  const sign = value > 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}`;
}

function formatSignedPercent(value: number): string {
  const sign = value > 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}%`;
}

function getStockFromProps(stock: Props['stocks'][number], index: number): DisplayStock {
  return {
    symbol: stock.symbol && stock.symbol.trim() ? stock.symbol : `STK${index + 1}`,
    name: stock.name && stock.name.trim() ? stock.name : 'Unknown Company',
    price: typeof stock.price === 'number' ? stock.price : 0,
    change: typeof stock.change === 'number' ? stock.change : 0,
    changePercent: typeof stock.changePercent === 'number' ? stock.changePercent : 0,
  };
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [stocks, setStocks] = useState<DisplayStock[]>([]);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [tickTime, setTickTime] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    const normalized = (props.stocks || []).map((stock, index) => getStockFromProps(stock, index));
    setStocks(normalized);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setTickTime(new Date());
    }, 1000);

    return () => {
      clearInterval(timer);
    };
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }

    setStocks((prev) => {
      const symbol = priceUpdate.latest?.symbol || '';
      let found = false;
      const next = prev.map((stock) => {
        if (stock.symbol !== symbol) {
          return stock;
        }
        found = true;
        return {
          ...stock,
          price: typeof priceUpdate.latest?.price === 'number' ? priceUpdate.latest.price : stock.price,
          change: typeof priceUpdate.latest?.change === 'number' ? priceUpdate.latest.change : stock.change,
          changePercent:
            typeof priceUpdate.latest?.changePercent === 'number' ? priceUpdate.latest.changePercent : stock.changePercent,
        };
      });

      if (!found) {
        next.push({
          symbol,
          name: 'Unknown Company',
          price: typeof priceUpdate.latest?.price === 'number' ? priceUpdate.latest.price : 0,
          change: typeof priceUpdate.latest?.change === 'number' ? priceUpdate.latest.change : 0,
          changePercent: typeof priceUpdate.latest?.changePercent === 'number' ? priceUpdate.latest.changePercent : 0,
        });
      }
      return next;
    });

    setLastUpdated(new Date());
    setFlashMap((prev) => ({
      ...prev,
      [priceUpdate.latest?.symbol || '']: Date.now(),
    }));
  }, [priceUpdate.latest]);

  const statusText = useMemo(() => {
    if (!marketStatus.latest?.status) {
      return 'Status unavailable';
    }
    return marketStatus.latest.status;
  }, [marketStatus.latest]);

  const statusVariant = useMemo(() => {
    if (marketStatus.latest?.status === 'open') {
      return 'success' as const;
    }
    if (marketStatus.latest?.status === 'closed') {
      return 'error' as const;
    }
    return 'warning' as const;
  }, [marketStatus.latest]);

  const lastUpdatedLabel = useMemo(() => {
    return lastUpdated.toLocaleTimeString();
  }, [lastUpdated, tickTime]);

  const empty = !stocks || stocks.length === 0;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" border radius="lg" shadow="sm">
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Market Watch
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {lastUpdatedLabel}
              </Text>
            </Stack>
            <Badge variant={statusVariant}>{statusText}</Badge>
          </Row>
        </Card>

        {empty ? (
          <Card padding="var(--ggui-spacing-6)" border radius="lg" shadow="sm">
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No stocks available
              </Text>
            </Stack>
          </Card>
        ) : (
          <Box>
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
                gap: 'var(--ggui-spacing-4)',
              }}
            >

              {stocks.map((stock, index) => {
                const positive = stock.change >= 0;
                const arrow = positive ? '▲' : '▼';
                const accentColor = positive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
                const flashColor = positive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)';

                return (
                  <Card
                    key={`${stock.symbol}-${flashMap[stock.symbol] || index}`}
                    padding="var(--ggui-spacing-4)"
                    border
                    radius="lg"
                    shadow="sm"
                     style={{
                       borderColor: accentColor,
                       animation: 'ggui-flash 500ms ease-out',
                       ['--ggui-flash-color' as string]: flashColor,
                        gridColumn: 'auto',
                     }}
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Heading level={3} color="var(--ggui-color-onSurface)">
                        {stock.symbol}
                      </Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name}
                      </Text>
                      <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                        {formatPrice(stock.price)}
                      </Text>
                      <Row justify="between" align="center">
                        <Text variant="body" color={accentColor}>
                          {formatSigned(stock.change)}
                        </Text>
                        <Text variant="body" color={accentColor} weight="semibold">
                          {arrow} {formatSignedPercent(stock.changePercent)}
                        </Text>
                      </Row>
                    </Stack>
                  </Card>
                );
              })}
            </Box>
          </Box>
        )}
      </Stack>
    </Container>

  );
}

