  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    if (!avatar && avatars.length > 0) {
      setAvatar(avatars[0]);
    }
  }, [avatar, avatars]);

  const nameError = useMemo(() => {
    if (!name.trim()) {
      return 'Name is required';
    }
    return '';
  }, [name]);

  const emailError = useMemo(() => {
    if (!email.trim()) {
      return 'Email is required';
    }
    if (!EMAIL_REGEX.test(email.trim())) {
      return 'Please enter a valid email address';
    }
    return '';
  }, [email]);

  const roleError = useMemo(() => {
    if (!role) {
      return 'Please select a role';
    }
    return '';
  }, [role]);

  const isStep1Valid = !nameError && !emailError && !!avatar;
  const isStep2Valid = !roleError;
  const canProceed = step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true;
  const progressValue = (step / 3) * 100;

  const goNext = useCallback(() => {
    if (step < 3 && canProceed) {
      setStep((prev) => prev + 1);
    }
  }, [step, canProceed]);

  const goBack = useCallback(() => {
    if (step > 1) {
      setStep((prev) => prev - 1);
    }
  }, [step]);

  const handleComplete = useCallback(() => {
    setSubmitted(true);
    if (!isStep1Valid || !isStep2Valid) {
      return;
    }
    const collectedData: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar: avatar || '',
      role,
      emailNotifications,
      theme,
    };
    complete(collectedData);
    (props as Props & { onComplete?: (data: ActionCompletePayload) => void }).onComplete?.(collectedData);
  }, [isStep1Valid, isStep2Valid, props, name, email, avatar, role, emailNotifications, theme, complete]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={2}>Onboarding Wizard</Heading>
              <Badge variant="primary" size="md">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm'}
            </Text>

            <Box
              padding="var(--ggui-spacing-4)"
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-lg)"
            >
              <Box
                key={step}
                style={{
                  animation: 'ggui-fadeIn 200ms ease-out',
                } as React.CSSProperties}
              >
                {step === 1 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Profile Setup</Heading>
                    <Input
                      label="Name"
                      value={name}
                      onChange={setName}
                      placeholder="Enter your full name"
                      required
                      error={submitted || step > 1 ? nameError : ''}
                    />
                    <Input
                      label="Email"
                      type="email"
                      value={email}
                      onChange={setEmail}
                      placeholder="you@example.com"
                      required
                      error={submitted || step > 1 ? emailError : ''}
                    />
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Choose Avatar</Text>
                      <Row gap="var(--ggui-spacing-3)" wrap>
                        {avatars.slice(0, 4).map((option) => (
                          <Card
                            key={option}
                            as={Clickable}
                            onClick={() => setAvatar(option)}
                            padding="var(--ggui-spacing-3)"
                            border
                            shadow="none"
                            radius="md"
                            style={{
                              borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                              background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                              transition: 'all 200ms ease-in-out',
                            } as React.CSSProperties}
                          >
                            <Stack align="center" gap="var(--ggui-spacing-1)">
                              <Text size="2xl" is="span">{option}</Text>
                              {avatar === option && <Badge variant="primary" size="sm">Selected</Badge>}
                            </Stack>
                          </Card>
                        ))}
                      </Row>
                    </Stack>
                  </Stack>
                )}

                {step === 2 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Preferences</Heading>
                    <Select
                      label="Role"
                      value={role}
                      onChange={setRole}
                      placeholder="Select your role"
                      options={roles.map((item) => ({ value: item, label: item }))}
                      error={submitted || step > 2 ? roleError : ''}
                      required
                    />
                    <Toggle
                      label="Email notifications"
                      checked={emailNotifications}
                      onChange={setEmailNotifications}
                    />
                    <Toggle
                      label="Dark theme"
                      checked={theme === 'dark'}
                      onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                    />
                  </Stack>
                )}

                {step === 3 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Review & Confirm</Heading>
                    <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
                      <Stack gap="var(--ggui-spacing-3)">
                        <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                        <Divider margin="var(--ggui-spacing-1)" />
                        <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                        <Divider margin="var(--ggui-spacing-1)" />
                        <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Row>
                        <Divider margin="var(--ggui-spacing-1)" />
                        <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                        <Divider margin="var(--ggui-spacing-1)" />
                        <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                        <Divider margin="var(--ggui-spacing-1)" />
                        <Row justify="between"><Text variant="label">Theme</Text><Text>{theme === 'dark' ? 'Dark' : 'Light'}</Text></Row>
                      </Stack>
                    </Card>
                  </Stack>
                )}
              </Box>
            </Box>

            <Row justify="between" align="center">
              <Button variant="ghost" onClick={goBack} disabled={step === 1}>
                Back
              </Button>
              <Row gap="var(--ggui-spacing-2)">
                {step < 3 ? (
                  <Button variant="primary" onClick={goNext} disabled={!canProceed}>
                    Next
                  </Button>
                ) : (
                  <>
                    <Button variant="outline" onClick={() => setStep(2)}>
                      Go Back
                    </Button>
                    <Button variant="primary" onClick={handleComplete} disabled={!isStep1Valid || !isStep2Valid}>
                      Complete Setup
                    </Button>
                  </>
                )}
              </Row>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}
